window.downloadImage = async function (e, t) {
  console.log("downloadImage called:", t);
  try {
    if (e.startsWith("data:")) {
      const a = document.createElement("a");
      a.href = e;
      a.download = t;
      a.style.display = "none";
      document.body.appendChild(a);
      setTimeout(() => {
        a.click();
        setTimeout(() => {
          document.body.removeChild(a);
        }, 100);
      }, 10);
      console.log("Downloaded via data URL method");
      return;
    }
    const a = await fetch(e);
    if (!a.ok) {
      throw new Error("Network response was not ok");
    }
    const n = await a.blob();
    if (typeof saveAs != "undefined") {
      console.log("Using FileSaver.js");
      saveAs(n, t);
      return;
    }
    const i = window.URL.createObjectURL(n);
    const o = document.createElement("a");
    o.href = i;
    o.download = t;
    o.style.display = "none";
    document.body.appendChild(o);
    setTimeout(() => {
      o.click();
      setTimeout(() => {
        window.URL.revokeObjectURL(i);
        document.body.removeChild(o);
      }, 100);
    }, 10);
    console.log("Downloaded via blob method");
  } catch (a) {
    console.error("Error downloading image:", a);
    try {
      if (!window.open(e, "_blank")) {
        throw new Error("Popup blocked");
      }
      m("Download", "<p class=\"mb-4\">Gambar dibuka di tab baru. Tekan dan tahan gambar untuk menyimpan.</p>");
    } catch (a) {
      m("Download Gambar", `\n                    <p class="mb-4 text-gray-700">Tekan dan tahan gambar di bawah, lalu pilih "Simpan Gambar" atau "Download Image".</p>\n                    <div class="bg-gray-100 p-4 rounded-lg">\n                        <img src="${e}" class="w-full rounded-lg border-2 border-gray-300" alt="${t}">\n                    </div>\n                    <p class="mt-4 text-sm text-gray-500">Nama file: ${t}</p>\n                `);
    }
  }
};
